using SchoolEnterprise.Models.Domain; using SchoolEnterprise.Services; namespace SchoolEnterprise.Repositories; public class ClassRepository(XmlStorageService storage) : BaseXmlRepository<ClassRoom>(storage){ protected override string FileName=>"classes.xml"; public ClassRoom? GetById(int id)=>GetAll().FirstOrDefault(x=>x.ClassRoomId==id); public void Add(ClassRoom i){var a=GetAll();a.Add(i);SaveAll(a);} public void Update(ClassRoom i){var a=GetAll();var x=a.FindIndex(t=>t.ClassRoomId==i.ClassRoomId);if(x>=0){a[x]=i;SaveAll(a);}} public void Delete(int id){var a=GetAll();a.RemoveAll(x=>x.ClassRoomId==id);SaveAll(a);} }
